const jsonText = `{
  "name": "سالم",
  "age": 25,
  "skills": ["HTML", "CSS"],
  "active": true
}`;
console.log(typeof jsonText); // string — نص وليس كائنًا بعد

const user = { name: "ليلى", scores: [90, 85] };

const text = JSON.stringify(user);
console.log(text);          // نص JSON

const back = JSON.parse(text);
console.log(back.name);     // ليلى — عاد كائنًا
console.log(back.scores[0]); // 90

const settings = { theme: "dark", fontSize: 18 };

// الحفظ: كائن -> نص
localStorage.setItem("settings", JSON.stringify(settings));

// الاسترجاع: نص -> كائن (مع قيمة احتياطية)
const saved = JSON.parse(localStorage.getItem("settings")) || {};
console.log("الوضع المحفوظ:", saved.theme);
console.log("حجم الخط:", saved.fontSize);

let visits = Number(localStorage.getItem("visits") || 0);
visits++;
localStorage.setItem("visits", visits);

document.querySelector("#counter").textContent =
  `عدد تشغيلات هذا المثال: ${visits}`;
console.log("أعد تشغيل المثال وشاهد الرقم يزيد!");
